 const load=async(silent=false)=>{if(!silent)setLoading(true);if(!silent)setLoadError('');try{const auth=await fetch('/api/auth',{cache:'no-store'});if(!auth.ok){if(silent)return;location.replace('/login?session=expired');return}const session=await auth.json();if(session.role!=='master'){if(silent)return;location.replace('/portal');return}setAuthorized(true);const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),15000);try{const d=await fetch('/api/diagnostics',{cache:'no-store',signal:controller.signal});if(!d.ok)throw new Error('diagnostics');const payload=await d.json();setItems(Array.isArray(payload)?payload:[])}finally{clearTimeout(timer)}}catch{if(!silent)setLoadError('Não foi possível carregar os dados. Tente novamente.')}finally{if(!silent)setLoading(false)}};
